joi_block.script:
triggered := false
if ((#MultiButton).multiButton_button3 == "pushed") {
if (triggered == false) {
tmp = (#Light #Bedroom).light_currentBrightness + 5
        if (80 < tmp) {
tmp = 80
}
(#Light #Bedroom).light_moveToBrightness(tmp, 0)
        triggered = true
}
}
else {
triggered = false
}

